use std::fmt::Debug;

struct Pair<'a, 'b> { 
    first: &'a str,
    second: &'b i32,
}

fn main() {
    let s1 = String::from("Hello World");
    let x = 10;
    let y = 20;

    // The Pair struct borrows from s1 and the stack variables x/y.
    // We must ensure 'a lives long enough for first, and 'b for second.
    let pair: Pair<'_ , '_> = Pair { 
        first: &s1,
        second: &x
    };

    println!("Pair created successfully:");
    println!("First: {}", pair.first);
    println!("Second: {}", pair.second);
}

use std::fmt::Write;

struct Container<'a> {
    data: &'a str,
}

impl<'a> Container<'a> {
    fn new(str_ref: &'a str) -> Self {
        Container { data: str_ref }
    }

    fn print_data(&self, output: &mut String) {
        writeln!(output, "Contained data: {}", self.data).unwrap();
    }
}

fn main() {
    let original_string = String::from("Hello World");
    let slice_ref: &'static str = "Static Data";

    // This demonstrates the lifetime tie to the input reference (&'a str)
    let container1 = Container::new(&original_string);
    let mut output1 = String::new();
    container1.print_data(&mut output1);
    println!("nOutput 1:n{}", output1);

    // The lifetime ensures that the data pointed to by container2 cannot outlive 'slice_ref'
    let container2 = Container::new(slice_ref);
    let mut output2 = String::new();
    container2.print_data(&mut output2);
    println!("nOutput 2:n{}", output2);
}

use std::fmt::Write;

struct Name<'a> {
    data: &'a str,
}

impl<'a> Name<'a> {
    fn new(s: &'a str) -> Self {
        Name { data: s }
    }

    fn print_name(&self) {
        println!("The name is: {}", self.data);
    }
}

fn main() {
    let source_string = String::from("Initial Data Source");
    let reference_lifetime = &source_string;

    let person_name = Name::new(reference_lifetime);
    person_name.print_name();
}

use std::fmt::Write;

struct ImmutableView<'a> { 
    data: &'a str,
}

impl<'a> ImmutableView<'a> {
    fn new(s: &'a str) -> Self {
        ImmutableView { data: s }
    }

    fn print_view(&self, writer: &mut String) {
        write!(writer, "Viewing: {}", self.data);
    }
}

fn main() {
    let source_string = String::from("Original data source");
    let view = ImmutableView::new(source_string.as_str());

    let mut output = String::new();
    view.print_view(&mut output);
    println!("{}", output);
}

use std::fmt::Debug;

struct Pair<'a, 'b> { 
    first: &'a str,
    second: &'b str,
}

impl<'a, 'b> Debug for Pair<'a, 'b> {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "Pair {{ first: \"{}\", second: \"{}\" }}", self.first, self.second)
    }
}

fn main() {
    let s1 = String::from("Hello World");
    let s2 = String::from("Rust Lifetime Example");

    let pair: Pair = Pair { 
        first: &s1,
        second: &s2,
    };

    println!("Created pair: {:?}", pair);
}
